content:
/* Global Reset and Base Styles */
* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

/* Ensure Chatbot is ALWAYS visible on all screens */
body .chatbot,
html .chatbot,
#root .chatbot,
.chatbot {
  position: fixed !important;
  z-index: 2147483647 !important;
  display: block !important;
  visibility: visible !important;
  opacity: 1 !important;
  pointer-events: auto !important;
  bottom: 0 !important;
  right: 0 !important;
}

body .bot-icon,
html .bot-icon,
#root .bot-icon,
.bot-icon {
  display: flex !important;
  visibility: visible !important;
  opacity: 1 !important;
  pointer-events: auto !important;
  z-index: 2147483647 !important;
}

body .chat-window,
html .chat-window,
#root .chat-window,
.chat-window {
  display: flex !important;
  visibility: visible !important;
  opacity: 1 !important;
  pointer-events: auto !important;
  z-index: 2147483647 !important;
}

:root {
  font-family: 'Inter', 'Segoe UI', 'Roboto', system-ui, Avenir, Helvetica, Arial, sans-serif;
  line-height: 1.5;
  font-weight: 400;
  color-scheme: dark;
  color: rgba(248, 250, 252, 0.95);
  background-color: #0f172a;
  font-synthesis: none;
  text-rendering: optimizeLegibility;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
  --primary-color: #3b82f6;
  --secondary-color: #6366f1;
  --accent-color: #10b981;
  --background-dark: #0f172a;
  --background-medium: #1e293b;
  --background-light: #334155;
  --text-light: rgba(248, 250, 252, 0.95);
  --text-muted: rgba(148, 163, 184, 0.9);
  --border-color: rgba(71, 85, 105, 0.3);
}

html, body {
  height: 100% !important;
  width: 100% !important;
  overflow: auto !important;
  position: relative;
}

body {
  margin: 0;
  background: var(--background-dark);
  color: var(--text-light);
  overflow-y: scroll;
  overflow-x: hidden;
}

#root {
  width: 100vw;
  min-height: 100vh;
  overflow: visible !important;
  position: relative;
  display: block;
}

h1, h2, h3, h4, h5, h6 {
  font-weight: 600;
  line-height: 1.2;
}

a {
  color: var(--primary-color);
  text-decoration: none;
  transition: color 0.3s ease;
}

a:hover {
  color: var(--secondary-color);
}

button {
  border-radius: 8px;
  border: 1px solid transparent;
  padding: 0.6em 1.2em;
  font-size: 1em;
  font-weight: 500;
  font-family: inherit;
  background: linear-gradient(45deg, var(--primary-color), var(--secondary-color));
  color: white;
  cursor: pointer;
  transition: all 0.3s ease;
  outline: none;
}

button:hover {
  transform: translateY(-2px);
  box-shadow: 0 5px 15px rgba(97, 218, 251, 0.3);
}

button:focus,
button:focus-visible {
  outline: 2px solid var(--primary-color);
  outline-offset: 2px;
}

button:active {
  transform: translateY(0);
}

.sr-only {
  position: absolute;
  width: 1px;
  height: 1px;
  padding: 0;
  margin: -1px;
  overflow: hidden;
  clip: rect(0, 0, 0, 0);
  white-space: nowrap;
  border: 0;
}

::-webkit-scrollbar {
  width: 8px;
}

::-webkit-scrollbar-track {
  background: rgba(255, 255, 255, 0.1);
}

::-webkit-scrollbar-thumb {
  background: var(--primary-color);
  border-radius: 4px;
}

::-webkit-scrollbar-thumb:hover {
  background: var(--secondary-color);
}
